import{_ as a,o as t,c as i,ae as r}from"./chunks/framework.B6gjLfeO.js";const u=JSON.parse('{"title":"Braze Configuration","description":"","frontmatter":{"title":"Braze Configuration","slug":"braze-configuration"},"headers":[],"relativePath":"developer-hub/braze-configuration.md","filePath":"developer-hub/braze-configuration.md"}'),s={name:"developer-hub/braze-configuration.md"};function n(o,e,h,l,d,p){return t(),i("div",null,[...e[0]||(e[0]=[r('<p><em>[Image: 1328]</em>.png &quot;Braze + branch.png&quot;)</p><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Braze unites data, teams, and technology to create brilliant brand messaging experiences for customers everywhere.</p><h2 id="how-does-it-work" tabindex="-1">How does it work? <a class="header-anchor" href="#how-does-it-work" aria-label="Permalink to &quot;How does it work?&quot;">​</a></h2><p>Once the Branch SDK is integrated into an app, Branch can detect which Branch Links are leading to installs, re-opens, and users&#39; actions. Enabling this integration and providing your relevant Ids will result in Branch automatically forwarding referred events to Braze, in the exact format Braze expects.</p><h3 id="branch-events-sent-to-braze" tabindex="-1">Branch Events Sent to Braze <a class="header-anchor" href="#branch-events-sent-to-braze" aria-label="Permalink to &quot;Branch Events Sent to Braze&quot;">​</a></h3><p>The events Branch sends to third party data tools varies based on the events the partner supports as well as whether or not you&#39;ve implemented the Branch SDK to measure said events.</p><p>Braze supports the following events:</p><ul><li>Installs</li></ul><p><em>Metadata sent to Braze</em><br> The metadata Branch sends to third party data tools varies based on the data the partner supports as well as whether or not you&#39;ve implemented the Branch SDK to measure said data.</p><table tabindex="0"><thead><tr><th>Branch Analytics Tag</th><th>Braze Data Placeholder Tag</th></tr></thead><tbody><tr><td>Campaign</td><td><code>campaign</code></td></tr><tr><td>Channel</td><td><code>source</code></td></tr><tr><td>Adgroup</td><td><code>adgroup</code></td></tr><tr><td>Ad</td><td><code>ad</code></td></tr></tbody></table><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><p>In order to enable Braze, you need to have completed the following:</p><ol><li><p>Admin access to your <a href="https://dashboard.branch.io/" target="_blank" rel="noreferrer">Branch Dashboard</a>.</p></li><li><p>Have the Advanced Data Feeds add-on enabled on your Branch account. Advanced Data Feeds can be included as an add-on to both the Engagement and Performance <a href="./packaging.html">products</a>.</p></li><li><p>Implemented the Branch SDK into your mobile app (<a href="./ios-sdk-overview.html">iOS</a> | <a href="./android-sdk-overview.html">Android</a>)</p><ul><li><a href="./track-branch-events.html">Track events</a></li></ul></li><li><p><a href="https://www.braze.com/docs/developer_guide/getting_started/sdk_overview" target="_blank" rel="noreferrer">Implement the Braze SDK</a></p><ul><li>Make sure to follow the steps in Braze&#39;s <a href="https://www.braze.com/documentation/Partner_Integrations/#branch" target="_blank" rel="noreferrer">documentation here</a>.</li></ul></li><li><p>Admin access to your Braze account.</p></li></ol><h2 id="enable-braze" tabindex="-1">Enable Braze <a class="header-anchor" href="#enable-braze" aria-label="Permalink to &quot;Enable Braze&quot;">​</a></h2><h2 id="_1-retrieve-ids-from-braze" tabindex="-1">1. Retrieve IDs from Braze <a class="header-anchor" href="#_1-retrieve-ids-from-braze" aria-label="Permalink to &quot;1. Retrieve IDs from Braze&quot;">​</a></h2><p>Before you can enable the integration in your Branch dashboard, you need to retrieve your credentials from your Braze account.</p><p>Branch requires these credentials to not only authenticate, but to ensure your Branch data is being sent to the correct account.</p><p>Branch requires the following credentials:</p><ul><li>API Key</li><li>Braze REST Endpoints</li></ul><p>To find your Braze API Key:</p><ol><li>On the Braze dashboard, navigate to the <strong>App Settings</strong> section, and click <strong>3rd Party Integrations</strong>.</li><li>From there, grab your API key (this will be the same for all attribution partners listed on the page).</li></ol><p>To find the correct Braze REST Endpoint, please refer to Braze&#39;s <a href="https://www.braze.com/docs/api/basics?redirected=true#endpoints" target="_blank" rel="noreferrer">documentation</a>.</p><h2 id="_2-connect-braze-in-branch" tabindex="-1">2. Connect Braze in Branch <a class="header-anchor" href="#_2-connect-braze-in-branch" aria-label="Permalink to &quot;2. Connect Braze in Branch&quot;">​</a></h2><p>In the Branch Dashboard in Data Feeds → <a href="https://dashboard.branch.io/data-feeds/integrations" target="_blank" rel="noreferrer"><strong>Data Integrations</strong> tab</a>, find and search for Braze.</p><p>Enter the API Key and Rest Endpoint from the previous step and hit <strong>Save</strong>.</p><h2 id="_3-pass-metadata-to-the-branch-sdk" tabindex="-1">3. Pass Metadata to the Branch SDK <a class="header-anchor" href="#_3-pass-metadata-to-the-branch-sdk" aria-label="Permalink to &quot;3. Pass Metadata to the Branch SDK&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">Developer Required</p><p>Developers on your mobile app are required for this step</p></div><p>Braze requires you to pass through the correct identifiers to the Branch SDKs. In order to do so, retrieve the ID from the Braze SDK and pass this value to Branch using the following method:</p><ul><li><code>setRequestMetadataKey()</code> method of the Branch SDKs:</li></ul><p><strong>NOTE</strong> You must set the correct key before initializing the Branch session. You must also initialize the Braze SDK before setting the request metadata in the Branch SDK.</p><div class="info custom-block"><p class="custom-block-title">February 2023 Updates</p><p>Prior to February 2023, our Branch attribution integration used the IDFV as the primary identifier to match iOS attribution data. It is not necessary for Braze customers using Objective-C to fetch the Braze device_id and sent to Branch upon install as there will be no disruption of service.</p><p>For those using the Swift SDK v5.7.0+, if you wish to continue using IDFV as the mutual identifier, you must ensure that the useUUIDAsDeviceId field is set to false so there is no disruption of the integration.</p><p>If set to true, you must implement the iOS device ID mapping for Swift in order to pass the Braze device_id to Branch upon app install in order for Braze to appropriately match iOS attributions.</p><p><strong>You must also disable and re-enable the Braze Data Integration connection on the Branch Dashboard</strong></p></div><div class="vp-code-group vp-adaptive-theme"><div class="tabs"><input type="radio" name="group-w5hRq" id="tab-vTX5E_A" checked><label data-title="Java" for="tab-vTX5E_A">Java</label><input type="radio" name="group-w5hRq" id="tab-kEYNJMG"><label data-title="Kotlin" for="tab-kEYNJMG">Kotlin</label><input type="radio" name="group-w5hRq" id="tab-l6v4UoZ"><label data-title="Swift" for="tab-l6v4UoZ">Swift</label><input type="radio" name="group-w5hRq" id="tab-fUQwC8P"><label data-title="Objective-C" for="tab-fUQwC8P">Objective-C</label></div><div class="blocks"><div class="language-java vp-adaptive-theme active"><button title="Copy Code" class="copy"></button><span class="lang">java</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Branch.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">getInstance</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">().</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">setRequestMetadata</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;$braze_install_id&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, Braze.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">getInstance</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(context).deviceId);</span></span></code></pre></div><div class="language-kotlin vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">kotlin</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Branch.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">getInstance</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">().</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">setRequestMetadata</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">$braze_install_id</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, Braze.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">getInstance</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(context).deviceId)</span></span></code></pre></div><div class="language-swift vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">swift</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Branch.getInstance.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">setRequestMetadata</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;$braze_install_id&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, braze.deviceId)</span></span></code></pre></div><div class="language-objectivec vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">objectivec</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>  [[Branch getInstance] setRequestMetadataKey:@&quot;$braze_install_id&quot; value: braze.deviceId];</span></span></code></pre></div></div></div><h2 id="_4-verify-data-sent" tabindex="-1">4. Verify Data Sent <a class="header-anchor" href="#_4-verify-data-sent" aria-label="Permalink to &quot;4. Verify Data Sent&quot;">​</a></h2><p>Once the above steps are complete, you are now ready to start launching campaigns. Branch-attributed conversions will be sent to Braze. To verify data is being sent from Branch to Braze, you can look at the Branch Dashboard&#39;s <a href="https://dashboard.branch.io/liveview/webhooks" target="_blank" rel="noreferrer">Liveview Webhook Records</a> and apply the following filter:</p><table tabindex="0"><thead><tr><th>Filter</th><th>Operator</th><th>Value</th></tr></thead><tbody><tr><td>webhook partner key</td><td>equals</td><td>di_braze</td></tr></tbody></table><div class="info custom-block"><p class="custom-block-title">Wait Period</p><p>Please be patient as data may take some time to flow through Branch&#39;s attribution systems and onto Braze. If data has not appeared in Braze after 30 minutes of completing a test conversion, review the above steps to see if you may have missed something.</p></div>',37)])])}const b=a(s,[["render",n]]);export{u as __pageData,b as default};
